import React, { useState } from 'react';
import { View, Text, StyleSheet, ScrollView, Alert, KeyboardAvoidingView, Platform } from 'react-native';
import { useTheme } from '../../context/ThemeContext';
import Input from '../../components/Input';
import Button from '../../components/Button';
import apiClient from '../../api/client';
import { spacing, fontSize, fontWeight, radius } from '../../theme';

export default function RegisterMessScreen({ navigation }: any) {
  const { colors } = useTheme();
  const [form, setForm] = useState({
    name: '', address: '', latitude: '', longitude: '',
    opening_time: '', closing_time: '', price_range: '',
  });
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});

  const set = (key: string) => (val: string) => setForm(f => ({ ...f, [key]: val }));

  const validate = () => {
    const e: Record<string, string> = {};
    if (!form.name) e.name = 'Required';
    if (!form.address) e.address = 'Required';
    if (!form.latitude) e.latitude = 'Required';
    if (!form.longitude) e.longitude = 'Required';
    if (!form.opening_time) e.opening_time = 'Required (HH:MM)';
    if (!form.closing_time) e.closing_time = 'Required (HH:MM)';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSubmit = async () => {
    if (!validate()) return;
    setLoading(true);
    try {
      await apiClient.post('/messes', {
        name: form.name, address: form.address,
        latitude: parseFloat(form.latitude),
        longitude: parseFloat(form.longitude),
        opening_time: form.opening_time,
        closing_time: form.closing_time,
        price_range: form.price_range || undefined,
      });
      Alert.alert('Success! 🎉', 'Your mess has been registered.', [
        { text: 'OK', onPress: () => navigation.goBack() },
      ]);
    } catch (err: any) {
      Alert.alert('Error', err.response?.data?.message ?? 'Failed to register mess');
    } finally {
      setLoading(false);
    }
  };

  return (
    <KeyboardAvoidingView style={{ flex: 1 }} behavior={Platform.OS === 'ios' ? 'padding' : undefined}>
      <ScrollView
        style={[styles.container, { backgroundColor: colors.background }]}
        contentContainerStyle={styles.content}
        keyboardShouldPersistTaps="handled"
      >
        <View style={[styles.card, { backgroundColor: colors.surface }]}>
          <Text style={[styles.sectionTitle, { color: colors.text }]}>🏪 Basic Info</Text>
          <Input label="Mess Name" placeholder="e.g. Sharma's Mess" value={form.name} onChangeText={set('name')} error={errors.name} />
          <Input label="Address" placeholder="Full address" value={form.address} onChangeText={set('address')} error={errors.address} />
        </View>

        <View style={[styles.card, { backgroundColor: colors.surface }]}>
          <Text style={[styles.sectionTitle, { color: colors.text }]}>📍 Location</Text>
          <Text style={[styles.hint, { color: colors.textSecondary }]}>
            Find your coordinates at maps.google.com → right-click your location
          </Text>
          <Input label="Latitude" placeholder="e.g. 18.5204" value={form.latitude} onChangeText={set('latitude')} keyboardType="numeric" error={errors.latitude} />
          <Input label="Longitude" placeholder="e.g. 73.8567" value={form.longitude} onChangeText={set('longitude')} keyboardType="numeric" error={errors.longitude} />
        </View>

        <View style={[styles.card, { backgroundColor: colors.surface }]}>
          <Text style={[styles.sectionTitle, { color: colors.text }]}>🕐 Hours & Pricing</Text>
          <Input label="Opening Time" placeholder="08:00" value={form.opening_time} onChangeText={set('opening_time')} error={errors.opening_time} />
          <Input label="Closing Time" placeholder="22:00" value={form.closing_time} onChangeText={set('closing_time')} error={errors.closing_time} />
          <Input label="Price Range (optional)" placeholder="e.g. ₹50–₹100" value={form.price_range} onChangeText={set('price_range')} />
        </View>

        <Button label="Register Mess" onPress={handleSubmit} loading={loading} style={{ marginTop: spacing.sm }} />
      </ScrollView>
    </KeyboardAvoidingView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  content: { padding: spacing.md, paddingBottom: spacing.xxl },
  card: { borderRadius: radius.xl, padding: spacing.lg, marginBottom: spacing.md },
  sectionTitle: { fontSize: fontSize.lg, fontWeight: fontWeight.bold, marginBottom: spacing.md },
  hint: { fontSize: fontSize.xs, marginBottom: spacing.md, lineHeight: 18 },
});
